module adder
(
  input          clock,
  input          reset,
  input   [7:0] a,
  input   [7:0] b,
  output [7:0]  sum
);

  reg [8:0] carry_out;

  always @(posedge clock) begin
    if (reset) begin
      carry_out <= 8'b0;
    end else begin
      carry_out <= a + b;
    end
  end

  assign sum = carry_out[7:0];

endmodule
